import axios from 'axios'
import type { Verb } from '../types/verb'

const BASE_URL = 'http://localhost:8002'

export async function fetchVerbs(): Promise<Verb[]> {
  const res = await axios.get(`${BASE_URL}/verbs`)
  return res.data
}

export async function createVerb(payload: Partial<Verb>): Promise<Verb> {
  const res = await axios.post(`${BASE_URL}/verbs`, payload)
  return res.data
}

export type Person = 'ich' | 'du' | 'er' | 'wir' | 'ihr' | 'sie'

export interface Tense {
  ich?: string
  du?: string
  er?: string
  wir?: string
  ihr?: string
  sie?: string
}

export interface Indikativ {
  prasens?: Tense
  prateritum?: Tense
  perfekt?: Tense
}

export interface Conjugations {
  indikativ?: Indikativ
}

export interface Verb {
  id: number
  word: string
  meaning: string
  conjugations?: Conjugations
}

import { useEffect, useState } from 'react'
import { fetchVerbs } from '../api/verbs'
import type { Verb } from '../types/verb'
import VerbItem from '../components/VerbItem'
import AddVerbModal from '../components/AddVerbModal'

interface Props {
  onBack: () => void
}

export default function VerbList({ onBack }: Props) {
  const [verbs, setVerbs] = useState<Verb[]>([])
  const [showAdd, setShowAdd] = useState(false)

  useEffect(() => {
    fetchVerbs().then(setVerbs)
  }, [])

  return (
    <div>
      <button onClick={onBack}>← 返回</button>
      <h2>动词列表</h2>

      <button onClick={() => setShowAdd(true)}>＋ 添加动词</button>

      <ul>
        {verbs.map(v => (
          <VerbItem key={v.id} verb={v} />
        ))}
      </ul>

      {showAdd && (
        <AddVerbModal
          onClose={() => setShowAdd(false)}
          onCreated={v => setVerbs(prev => [...prev, v])}
        />
      )}
    </div>
  )
}

import { useState } from 'react'
import type { Verb } from '../types/verb'
import ConjugationTable from './ConjugationTable'

export default function VerbItem({ verb }: { verb: Verb }) {
  const [open, setOpen] = useState(false)

  return (
    <li style={{ marginBottom: 12 }}>
      <strong>{verb.word}</strong> — {verb.meaning}
      <br />
      <button onClick={() => setOpen(o => !o)}>
        {open ? '隐藏变位' : '查看变位'}
      </button>

      {open && <ConjugationTable conjugations={verb.conjugations} />}
    </li>
  )
}

import type { Conjugations } from '../types/verb'

const persons = ['ich', 'du', 'er', 'wir', 'ihr', 'sie'] as const

export default function ConjugationTable({
  conjugations,
}: {
  conjugations?: Conjugations
}) {
  const indikativ = conjugations?.indikativ

  if (!indikativ) {
    return <p>暂无变位信息</p>
  }

  return (
    <table border={1} cellPadding={6} style={{ marginTop: 8 }}>
      <thead>
        <tr>
          <th></th>
          <th>现在时</th>
          <th>过去时</th>
          <th>完成时</th>
        </tr>
      </thead>
      <tbody>
        {persons.map(p => (
          <tr key={p}>
            <td>{p}</td>
            <td>{indikativ.prasens?.[p] || '—'}</td>
            <td>{indikativ.prateritum?.[p] || '—'}</td>
            <td>{indikativ.perfekt?.[p] || '—'}</td>
          </tr>
        ))}
      </tbody>
    </table>
  )
}

import { useMemo, useState } from 'react'
import { createVerb } from '../api/verbs'
import type { Verb, Conjugations, Tense } from '../types/verb'

interface Props {
  onClose: () => void
  onCreated: (verb: Verb) => void
}

type TenseKey = 'prasens' | 'prateritum' | 'perfekt'
type PersonKey = 'ich' | 'du' | 'er' | 'wir' | 'ihr' | 'sie'

const PERSONS: PersonKey[] = ['ich', 'du', 'er', 'wir', 'ihr', 'sie']
const TENSES: { key: TenseKey; label: string }[] = [
  { key: 'prasens', label: '现在时' },
  { key: 'prateritum', label: '过去时' },
  { key: 'perfekt', label: '完成时' },
]

function makeEmptyTense(): Tense {
  return { ich: '', du: '', er: '', wir: '', ihr: '', sie: '' }
}

export default function AddVerbModal({ onClose, onCreated }: Props) {
  const [word, setWord] = useState('')
  const [meaning, setMeaning] = useState('')

  // 18 个输入框：3 个时态 * 6 个人称
  const [forms, setForms] = useState<Record<TenseKey, Tense>>({
    prasens: makeEmptyTense(),
    prateritum: makeEmptyTense(),
    perfekt: makeEmptyTense(),
  })

  const canSubmit = useMemo(() => word.trim() !== '' && meaning.trim() !== '', [word, meaning])

  function setFormValue(tense: TenseKey, person: PersonKey, value: string) {
    setForms(prev => ({
